      var statusLabels2 = {new:'\uD83D\uDFE2 Новый',contacted:'\uD83D\uDCAC Связь',in_progress:'\uD83D\uDD04 Работа',checking:'\uD83D\uDD0D Проверка',done:'\u2705 Готов',rejected:'\u274C Откл'};
